import {{json}}
import csv
from pathlib import {{Path}}
from dataclasses import dataclass, {{asdict}}

@dataclass
class Student:
    name: str
    score: {{float}}

# JSON serializace
def save_json(students: list[Student], path: str):
    with open(path, 'w', encoding={{'"utf-8"'}}) as f:
        json.{{dump}}([asdict(s) for s in students], f, ensure_ascii=False, indent=2)

def load_json(path: str) -> list[Student]:
    with open(path, encoding='utf-8') as f:
        data = json.{{load}}(f)
    return [Student(**d) for d in {{data}}]

# CSV zápis
def save_csv(students: list[Student], path: str):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.{{DictWriter}}(f, fieldnames=['name', 'score'])
        writer.{{writeheader}}()
        writer.writerows([asdict(s) for s in {{students}}])

const {{fs}} = require('fs');
